"use strict";exports.id=1301,exports.ids=[1301],exports.modules={11301:a=>{a.exports=JSON.parse('{"title":"\xc0 Propos de Wayfera","subtitle":"Votre partenaire de confiance dans la cr\xe9ation d\'exp\xe9riences de voyage inoubliables \xe0 travers le monde","story":{"title":"Notre Histoire","p1":"Fond\xe9e en 2010, Wayfera a commenc\xe9 avec une mission simple : rendre les exp\xe9riences de voyage de classe mondiale accessibles \xe0 tous. Ce qui a commenc\xe9 comme une petite \xe9quipe de voyageurs passionn\xe9s est devenu un r\xe9seau mondial d\'experts en voyages.","p2":"Au fil des ans, nous avons aid\xe9 des milliers de voyageurs \xe0 d\xe9couvrir des destinations incroyables, \xe0 cr\xe9er des souvenirs durables et \xe0 d\xe9couvrir des cultures du monde entier.","p3":"Aujourd\'hui, nous continuons d\'innover et d\'\xe9largir nos services, en gardant toujours les r\xeaves et la satisfaction de nos clients au cœur de tout ce que nous faisons."},"values":{"title":"Nos Valeurs","excellence":{"title":"Excellence","description":"Nous visons l\'excellence dans chaque voyage que nous cr\xe9ons"},"customerFirst":{"title":"Client d\'Abord","description":"Votre satisfaction est notre priorit\xe9 absolue"},"globalReach":{"title":"Port\xe9e Mondiale","description":"Vous connecter \xe0 des destinations dans le monde entier"},"passion":{"title":"Passion","description":"Nous aimons ce que nous faisons et cela se voit"}},"stats":{"countries":"Pays","clients":"Clients Satisfaits","destinations":"Destinations","support":"Support"}}')}};